queries.sphinxql:
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 FACET ts FACET ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='strict' FACET ts FACET ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='auto' FACET ts FACET ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='max' FACET ts FACET ver;;


SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='strict' FACET ts MODE auto FACET ver MODE max FACET gid MODE strict;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='auto' FACET ts ALL FILTERS FACET ver ALL FILTERS MODE max;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='strict' FACET gid FILTERS ts MODE max;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='max' FACET gid EXCLUDE FILTERS ver MODE auto;;


SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 FACET gid FILTERS ts;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 FACET gid EXCLUDE FILTERS ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 FACET ts FILTERS ts, ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 FACET gid EXCLUDE FILTERS ts, ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) AND ver IN('20') LIMIT 0 OPTION facet_filter_mode='strict' FACET ts ALL FILTERS MODE max;;


SELECT count(*) FROM facet_scope LIMIT 0 OPTION facet_filter_mode='max' FACET ts MODE max FACET ver MODE max;;
SELECT count(*) FROM facet_scope WHERE ver IN('20') LIMIT 0 OPTION facet_filter_mode='auto' FACET ver;;
SELECT count(*) FROM facet_scope WHERE ts IN (10,20) LIMIT 0 OPTION facet_filter_mode='max' FACET gid MODE strict FACET ver MODE max;;


SELECT count(*) FROM facet_scope LIMIT 0 OPTION facet_filter_mode='bogus' FACET ts;;
SELECT count(*) FROM facet_scope LIMIT 0 FACET ts MODE bogus;;
SELECT count(*) FROM facet_scope LIMIT 0 FACET ts FILTERS;;
SELECT count(*) FROM facet_scope LIMIT 0 FACET ts EXCLUDE FILTERS;;
SELECT count(*) FROM facet_scope LIMIT 0 FACET ts MODE max FILTERS ver;;
